import React, { useState, useRef } from 'react';
import { view } from '@forge/bridge';

const STATUS_COLORS = {
  'To Do':       { bg: '#DFE1E6', text: '#42526E', border: '#97A0AF' },
  'In Progress': { bg: '#DEEBFF', text: '#0747A6', border: '#0052CC' },
  'In Review':   { bg: '#EAE6FF', text: '#403294', border: '#5243AA' },
  'Review':      { bg: '#EAE6FF', text: '#403294', border: '#5243AA' },
  'Done':        { bg: '#E3FCEF', text: '#006644', border: '#00875A' },
  'Canceled':    { bg: '#F4F5F7', text: '#97A0AF', border: '#C1C7D0' },
  'Blocked':     { bg: '#FFEBE6', text: '#BF2600', border: '#DE350B' },
};

function getStatusColor(statusName) {
  return STATUS_COLORS[statusName] || { bg: '#DEEBFF', text: '#0747A6', border: '#0052CC' };
}

const PRIORITY_ICON = {
  Highest: '🔴', High: '🟠', Medium: '🟡', Low: '🔵', Lowest: '⚪',
};

function parseDate(str) {
  if (!str) return null;
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}

function daysBetween(a, b) {
  return Math.round((b - a) / 86400000);
}

function fmtDate(date) {
  if (!date) return '—';
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return `${months[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
}

function addDays(date, n) {
  const d = new Date(date);
  d.setDate(d.getDate() + n);
  return d;
}

export default function GanttBar({ issue, viewStart, dayWidth, rowHeight, barPadding, totalDays, squadColor }) {
  const [tooltip, setTooltip] = useState(null);
  const barRef = useRef(null);

  const { key, fields } = issue;
  const summary = fields.summary || '';
  const status = fields.status?.name || 'To Do';
  const priority = fields.priority?.name || 'Medium';
  const assignee = fields.assignee?.displayName || 'Unassigned';

  let startDate = parseDate(fields.customfield_10015);
  let endDate = parseDate(fields.duedate);

  if (startDate && !endDate) endDate = addDays(startDate, 7);
  else if (!startDate && endDate) startDate = addDays(endDate, -7);
  else if (!startDate && !endDate) {
    const ref = new Date();
    startDate = addDays(ref, -3);
    endDate = addDays(ref, 3);
  }

  const startOffset = daysBetween(viewStart, startDate);
  const endOffset = daysBetween(viewStart, endDate) + 1;
  const clippedStart = Math.max(0, startOffset);
  const clippedEnd = Math.min(totalDays, endOffset);

  if (clippedEnd <= clippedStart) return null;

  const barLeft = clippedStart * dayWidth;
  const barWidth = Math.max((clippedEnd - clippedStart) * dayWidth, dayWidth * 0.5);
  const overflowLeft = startOffset < 0;
  const overflowRight = endOffset > totalDays;
  const statusColor = getStatusColor(status);
  const barHeight = rowHeight - barPadding * 2;
  const barBg = squadColor ? squadColor.bg : statusColor.bg;
  const barBorder = squadColor ? squadColor.border : statusColor.border;
  const barText = squadColor ? squadColor.text : statusColor.text;

  return (
    <>
      <div
        ref={barRef}
        onClick={() => view.open({ type: 'jiraIssue', key })}
        onMouseEnter={(e) => {
          const rect = barRef.current?.getBoundingClientRect();
          setTooltip({ x: rect ? rect.left : e.clientX, y: rect ? rect.bottom + 6 : e.clientY + 12 });
        }}
        onMouseLeave={() => setTooltip(null)}
        onMouseDown={(e) => { e.currentTarget.style.filter = 'brightness(0.92)'; }}
        onMouseUp={(e) => { e.currentTarget.style.filter = ''; }}
        style={{
          position: 'absolute',
          left: barLeft,
          top: barPadding,
          width: barWidth,
          height: barHeight,
          background: barBg,
          border: `1.5px solid ${barBorder}`,
          borderRadius: overflowLeft ? '0 6px 6px 0' : overflowRight ? '6px 0 0 6px' : '6px',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'center',
          paddingLeft: overflowLeft ? '4px' : '8px',
          paddingRight: overflowRight ? '4px' : '8px',
          overflow: 'hidden',
          zIndex: 2,
          boxSizing: 'border-box',
          transition: 'filter 0.1s',
          userSelect: 'none',
        }}
      >
        {overflowLeft && <span style={{ color: barText, marginRight: 3, fontSize: 10, opacity: 0.7 }}>‹</span>}
        <span style={{ fontSize: '10px', fontWeight: 700, color: barText, opacity: 0.8, whiteSpace: 'nowrap', marginRight: 4, flexShrink: 0 }}>
          {key}
        </span>
        <span style={{ fontSize: '11px', fontWeight: 500, color: barText, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
          {summary}
        </span>
        {overflowRight && <span style={{ color: barText, marginLeft: 3, fontSize: 10, opacity: 0.7 }}>›</span>}
      </div>

      {tooltip && (
        <Tooltip
          issue={issue}
          x={tooltip.x}
          y={tooltip.y}
          startDate={startDate}
          endDate={endDate}
          status={status}
          priority={priority}
          assignee={assignee}
          statusColor={statusColor}
        />
      )}
    </>
  );
}

function Tooltip({ issue, x, y, startDate, endDate, status, priority, assignee, statusColor }) {
  const { key, fields } = issue;
  const summary = fields.summary || '';
  const project = fields.project?.name || '';
  const safeX = Math.min(x, window.innerWidth - 280);
  const safeY = Math.min(y, window.innerHeight - 180);

  return (
    <div style={{
      position: 'fixed', left: safeX, top: safeY, width: 260,
      background: '#fff', border: '1px solid #DFE1E6', borderRadius: '6px',
      boxShadow: '0 4px 16px rgba(0,0,0,0.15)', zIndex: 9999,
      padding: '12px', pointerEvents: 'none', fontSize: '12px', color: '#172B4D',
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '6px' }}>
        <span style={{ background: '#DEEBFF', color: '#0747A6', borderRadius: '4px', padding: '1px 6px', fontWeight: 700, fontSize: '11px' }}>
          {key}
        </span>
        <span style={{ color: '#6B778C', fontSize: '11px' }}>{project}</span>
      </div>
      <div style={{ fontWeight: 600, fontSize: '13px', marginBottom: '10px', lineHeight: '1.4' }}>{summary}</div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px' }}>
        <TooltipField label="Status">
          <span style={{ background: statusColor.bg, color: statusColor.text, border: `1px solid ${statusColor.border}`, borderRadius: '4px', padding: '1px 6px', fontSize: '11px', fontWeight: 600 }}>
            {status}
          </span>
        </TooltipField>
        <TooltipField label="Priority">{PRIORITY_ICON[priority] || '·'} {priority}</TooltipField>
        <TooltipField label="Start">{fmtDate(startDate)}</TooltipField>
        <TooltipField label="Due">{fmtDate(endDate)}</TooltipField>
        <TooltipField label="Assignee" wide>{assignee}</TooltipField>
      </div>
      <div style={{ marginTop: '8px', fontSize: '11px', color: '#97A0AF' }}>Click to open in Jira</div>
    </div>
  );
}

function TooltipField({ label, children, wide }) {
  return (
    <div style={{ gridColumn: wide ? '1 / -1' : 'auto' }}>
      <div style={{ fontSize: '10px', fontWeight: 600, color: '#97A0AF', marginBottom: '2px', textTransform: 'uppercase', letterSpacing: '0.4px' }}>{label}</div>
      <div style={{ fontSize: '12px', color: '#172B4D' }}>{children}</div>
    </div>
  );
}
